mapper.update:
UPDATE custom_sections
section_title = #{sectionTitle}, content = #{content}, sort_order = #{sortOrder}, updated_at = NOW()
WHERE id = #{id} AND resume_id = #{resumeId}

mapper.select:
SELECT id, resume_id, section_title, content, sort_order, created_at, updated_at
FROM custom_sections
WHERE id = #{id} AND resume_id = #{resumeId}

